import React, { useState } from 'react';
import Wallet from './components/Wallet';
import MintForm from './components/MintForm';
import Marketplace from './components/Marketplace';
import NFTs from './components/NFTs';
import RoyaltyDashboard from './components/RoyaltyDashboard';
import NetworkStatus from './components/NetworkStatus';
import './styles.css';

function App() {
  const [activeTab, setActiveTab] = useState('marketplace');

  return (
    <div className="app-container">
      <header className="header">
        <div className="logo">🎨 NFT Marketplace</div>
        
        <nav className="nav-links">
          <a 
            href="#marketplace" 
            className={`nav-link ${activeTab === 'marketplace' ? 'active' : ''}`}
            onClick={() => setActiveTab('marketplace')}
          >
            Marketplace
          </a>
          <a 
            href="#mint" 
            className={`nav-link ${activeTab === 'mint' ? 'active' : ''}`}
            onClick={() => setActiveTab('mint')}
          >
            Mint NFT
          </a>
          <a 
            href="#my-nfts" 
            className={`nav-link ${activeTab === 'my-nfts' ? 'active' : ''}`}
            onClick={() => setActiveTab('my-nfts')}
          >
            My NFTs
          </a>
          <a 
            href="#royalties" 
            className={`nav-link ${activeTab === 'royalties' ? 'active' : ''}`}
            onClick={() => setActiveTab('royalties')}
          >
            💰 Royalties
          </a>
        </nav>
        
        <Wallet />
      </header>

      <main>
        {activeTab === 'marketplace' && <Marketplace />}
        {activeTab === 'mint' && <MintForm />}
        {activeTab === 'my-nfts' && <NFTs />}
        {activeTab === 'royalties' && <RoyaltyDashboard />}
      </main>

      <footer style={{
        marginTop: '60px',
        paddingTop: '20px',
        borderTop: '1px solid #333',
        textAlign: 'center',
        color: '#888',
        fontSize: '14px'
      }}>
        <p>NFT Marketplace • Built with React & Hardhat • Supports ERC-721 & ERC-1155</p>
        <p style={{ marginTop: '10px', fontSize: '12px' }}>
          Contract Addresses: 
          <br />
          Marketplace: 0x5FbDB2315678afecb367f032d93F642f64180aa3
          <br />
          ERC-721: 0xe7f1725E7734CE288F8367e1Bb143E90bb3F0512
          <br />
          ERC-1155: 0x9fE46736679d2D6a4F94925474F7d4a4a4a4a4a4
        </p>
      </footer>
    </div>
  );
}

export default App;
